// Parse action type and extract parameters from the intent classifier output
const intentData = $input.item.json;

// Extract intent details from the classifier response
let intentContent = {};
try {
  if (typeof intentData.choices?.[0]?.message?.content === 'string') {
    intentContent = JSON.parse(intentData.choices[0].message.content);
  } else {
    intentContent = intentData;
  }
} catch (e) {
  intentContent = intentData;
}

const details = intentContent.details || {};
const message = intentData.message || '';

// Determine action type from details or message content
let actionType = 'unknown';
let params = {};

// Calendar operations
if (message.match(/créer.*rendez-vous|ajouter.*calendrier|planifier|rdv/i) || details.action === 'calendar_create') {
  actionType = 'calendar_create';
  params = {
    summary: details.title || 'Rendez-vous',
    description: details.description || message,
    start: details.start_time || new Date(Date.now() + 86400000).toISOString(), // +24h default
    end: details.end_time || new Date(Date.now() + 90000000).toISOString(), // +25h default
    attendees: details.attendees || []
  };
}

// Email send
else if (message.match(/envoyer.*email|mail à|écrire à/i) || details.action === 'email_send') {
  actionType = 'email_send';
  params = {
    to: details.recipient || '',
    subject: details.subject || 'Message automatique',
    body: details.body || message,
    attachments: details.attachments || []
  };
}

// Email summary
else if (message.match(/résumer.*emails|synthèse.*messages|derniers mails/i) || details.action === 'email_summary') {
  actionType = 'email_summary';
  params = {
    maxResults: details.max_results || 20,
    query: details.query || 'is:unread',
    afterDate: details.after_date || new Date(Date.now() - 7 * 86400000).toISOString() // -7 days
  };
}

// File search
else if (message.match(/chercher.*fichier|trouver.*document|recherche.*drive/i) || details.action === 'file_search') {
  actionType = 'file_search';
  params = {
    query: details.search_query || message.replace(/chercher|trouver|recherche/gi, '').trim(),
    mimeType: details.mime_type || null,
    folder: details.folder_id || null
  };
}

return {
  actionType,
  params,
  originalMessage: message,
  intentDetails: intentContent
};

