// Aggregate action results into a structured response
const actionType = $('Action Parser').item.json.actionType;
const originalMessage = $('Action Parser').item.json.originalMessage;

let result = {
  success: true,
  actionType,
  originalMessage,
  result: '',
  data: {}
};

try {
  switch (actionType) {
    case 'calendar_create':
      const calEvent = $input.item.json;
      result.result = `✅ Rendez-vous créé avec succès:\n📅 ${calEvent.summary}\n🕐 ${new Date(calEvent.start.dateTime).toLocaleString('fr-FR')}\n🔗 ${calEvent.htmlLink}`;
      result.data = {
        eventId: calEvent.id,
        link: calEvent.htmlLink,
        start: calEvent.start.dateTime
      };
      break;

    case 'email_send':
      const email = $input.item.json;
      result.result = `✅ Email envoyé avec succès\n📧 À: ${email.to || 'destinataire'}\n📝 Sujet: ${email.subject}`;
      result.data = {
        messageId: email.id,
        threadId: email.threadId
      };
      break;

    case 'email_summary':
      const summary = $input.item.json;
      result.result = `📬 Résumé des emails:\n\n${summary.choices?.[0]?.message?.content || 'Aucun email récent'}`;
      result.data = {
        emailCount: $items('Gmail Read').length,
        summary: summary.choices?.[0]?.message?.content
      };
      break;

    case 'file_search':
      const files = $input.all();
      if (files.length === 0) {
        result.result = '🔍 Aucun fichier trouvé pour cette recherche.';
      } else {
        const fileList = files.slice(0, 10).map((f, i) => 
          `${i+1}. ${f.json.name} (${(f.json.size / 1024).toFixed(1)} KB)\n   🔗 ${f.json.webViewLink}`
        ).join('\n');
        result.result = `🔍 ${files.length} fichier(s) trouvé(s):\n\n${fileList}`;
        result.data = {
          fileCount: files.length,
          files: files.slice(0, 10).map(f => ({
            id: f.json.id,
            name: f.json.name,
            link: f.json.webViewLink,
            size: f.json.size,
            mimeType: f.json.mimeType
          }))
        };
      }
      break;

    default:
      result.success = false;
      result.result = '❌ Type d\'action non reconnu.';
      break;
  }
} catch (error) {
  result.success = false;
  result.result = `❌ Erreur lors de l'exécution: ${error.message}`;
  result.error = error.message;
}

return result;
